class Solution {

    public List<Integer> parseNestedParens(String paren_string) {
        List<Integer> result = new ArrayList<>();
        int maxDepth = 0;
        int currentDepth = 0;
        for (int i = 0; i < paren_string.length(); i++) {
            char c = paren_string.charAt(i);
            if (c == '(') {
                currentDepth++;
                if (currentDepth > maxDepth) {
                    maxDepth = currentDepth;
                }
            } else if (c == ')') {
                currentDepth--;
            } else if (c == ' ') {
                result.add(maxDepth);
                maxDepth = 0;
                currentDepth = 0;
            }
        }
        result.add(maxDepth);
        return result;
    }
}

