class Solution {

    public int greatestCommonDivisor(int a, int b) {
        int tempA = a;
        int tempB = b;
        if (tempA < 0) {
            tempA = tempA * -1;
        }
        if (tempB < 0) {
            tempB = tempB * -1;
        }
        while (tempB != 0) {
            int remainder = tempA % tempB;
            tempA = tempB;
            tempB = remainder;
        }
        return tempA;
    }
}

