class Solution {

    public int countDistinctCharacters(String string) {
        int distinctCount = 0;
        String lowerString = string.toLowerCase();
        int effectiveLen = lowerString.length();
        while (effectiveLen > 0 && lowerString.charAt(effectiveLen - 1) == ' ') {
            effectiveLen--;
        }
        char[] distinctTable = new char[100];
        for (int i = 0; i < effectiveLen; i++) {
            char ch = lowerString.charAt(i);
            boolean found = false;
            for (int j = 0; j < distinctCount && !found; j++) {
                if (distinctTable[j] == ch) {
                    found = true;
                }
            }
            if (!found) {
                distinctTable[distinctCount++] = ch;
            }
        }
        return distinctCount;
    }
}

