class Solution {

    public String sortNumbers(String numbers) {

        String[] words = new String[10];
        int[] nums = new int[10];
        int count = 0;
        int pos = 0;

        String[] tokens = numbers.split(" ");
        for (String token : tokens) {
            if (token.trim().isEmpty()) continue;
            if (count >= 10) break;
            words[count++] = token;
        }

        for (int i = 0; i < count; i++) {
            String w = words[i].trim();
            switch (w) {
                case "zero":   nums[i] = 0; break;
                case "one":    nums[i] = 1; break;
                case "two":    nums[i] = 2; break;
                case "three":  nums[i] = 3; break;
                case "four":   nums[i] = 4; break;
                case "five":   nums[i] = 5; break;
                case "six":    nums[i] = 6; break;
                case "seven":  nums[i] = 7; break;
                case "eight":  nums[i] = 8; break;
                case "nine":   nums[i] = 9; break;
                default:       nums[i] = -1; break;
            }
        }

        for (int i = 0; i < count - 1; i++) {
            for (int j = 0; j < count - i - 1; j++) {
                if (nums[j] > nums[j + 1]) {
                    int tmp = nums[j];
                    nums[j] = nums[j + 1];
                    nums[j + 1] = tmp;
                }
            }
        }

        StringBuilder result = new StringBuilder();
        for (int i = 0; i < count; i++) {
            String tmp;
            switch (nums[i]) {
                case 0: tmp = "zero"; break;
                case 1: tmp = "one"; break;
                case 2: tmp = "two"; break;
                case 3: tmp = "three"; break;
                case 4: tmp = "four"; break;
                case 5: tmp = "five"; break;
                case 6: tmp = "six"; break;
                case 7: tmp = "seven"; break;
                case 8: tmp = "eight"; break;
                case 9: tmp = "nine"; break;
                default: tmp = ""; break;
            }
            if (i == 0) {
                result.append(tmp);
            } else {
                result.append(' ').append(tmp);
            }
        }

        return result.toString();
    }
}

