class Solution {

    public List<Double> findClosestElements(List<Double> numbers) {
        int arraySize = numbers.size();
        double minDiff = 999999;
        double closest1 = 0;
        double closest2 = 0;
        for (int i = 0; i < arraySize; i++) {
            for (int j = i + 1; j < arraySize; j++) {
                double currentDiff = Math.abs(numbers.get(i) - numbers.get(j));
                if (currentDiff < minDiff) {
                    minDiff = currentDiff;
                    closest1 = numbers.get(i);
                    closest2 = numbers.get(j);
                }
            }
        }
        if (closest1 > closest2) {
            double temp = closest1;
            closest1 = closest2;
            closest2 = temp;
        }
        List<Double> result = new ArrayList<>();
        result.add(closest1);
        result.add(closest2);
        return result;
    }
}

