class Solution {

    public List<Double> rescaleToUnit(List<Double> numbers) {
        int count = numbers.size();
        double minValue = numbers.get(0);
        for (int i = 1; i < count; i++) {
            if (numbers.get(i) < minValue) {
                minValue = numbers.get(i);
            }
        }
        double maxValue = numbers.get(0);
        for (int i = 1; i < count; i++) {
            if (numbers.get(i) > maxValue) {
                maxValue = numbers.get(i);
            }
        }
        double range = maxValue - minValue;
        List<Double> result = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            double temp = numbers.get(i) - minValue;
            result.add(temp / range);
        }
        return result;
    }
}

