class Solution {

    public int strlen(String string) {
        int result = 0;
        int length = 0;
        int startPos = 1;
        int endPos = 0;
        int i = 1;

        char[] lString = new char[100];
        for (int j = 0; j < 100; j++) {
            lString[j] = ' ';
        }

        if (string != null && string.length() > 0) {
            for (int k = 0; k < Math.min(string.length(), 100); k++) {
                lString[k] = string.charAt(k);
            }
        }

        result = 0;
        length = 0;
        startPos = 1;
        endPos = 0;
        i = 1;

        for (i = 1; i <= 100; i++) {
            if (lString[i - 1] != ' ') {
                startPos = i;
                break;
            }
        }

        if (i > 100) {
            result = 0;
            return result;
        }

        for (i = 100; i >= 1; i--) {
            if (lString[i - 1] != ' ') {
                endPos = i;
                break;
            }
        }

        length = endPos - startPos + 1;
        result = length;

        return result;
    }
}

