class Solution {

    public List<Integer> factorize(int n) {
        List<Integer> result = new ArrayList<>();
        if (n <= 1) {
            return result;
        }
        int factor = 2;
        while (n != 1) {
            while (n % factor == 0) {
                result.add(factor);
                n /= factor;
            }
            factor++;
            if (factor * factor > n && n > 1) {
                result.add(n);
                n = 1;
            }
        }
        return result;
    }
}

