class Solution {

    public String flipCase(String string) {
        char[] result = new char[string.length()];
        for (int i = 0; i < string.length(); i++) {
            char c = string.charAt(i);
            if (c >= 'A' && c <= 'Z') {
                result[i] = (char) (c + 32);
            } else if (c >= 'a' && c <= 'z') {
                result[i] = (char) (c - 32);
            } else {
                result[i] = c;
            }
        }
        return new String(result);
    }
}

