class Solution {

    public List<Integer> unique(List<Integer> l) {
        int len = 9;
        int[] result = new int[100];
        for (int i = 0; i < 100; i++) {
            result[i] = 0;
        }
        for (int i = 0; i < len - 1; i++) {
            for (int j = 0; j < len - i - 1; j++) {
                if (l.get(j) > l.get(j + 1)) {
                    int tmp = l.get(j);
                    l.set(j, l.get(j + 1));
                    l.set(j + 1, tmp);
                }
            }
        }
        int k = 0;
        result[k] = l.get(0);
        for (int i = 1; i < len; i++) {
            if (l.get(i) != result[k]) {
                k++;
                result[k] = l.get(i);
            }
        }
        List<Integer> resList = new ArrayList<>();
        for (int i = 0; i <= k; i++) {
            resList.add(result[i]);
        }
        return resList;
    }
}

