class Solution {

    public int fizzBuzz(int n) {
        int result = 0;
        int sevenCount = 0;
        for (int currentNum = 1; currentNum < n; currentNum++) {
            if (currentNum % 11 == 0 || currentNum % 13 == 0) {
                int tempNum = currentNum;
                while (tempNum != 0) {
                    int digit = tempNum % 10;
                    if (digit == 7) {
                        sevenCount++;
                    }
                    tempNum = tempNum / 10;
                }
            }
        }
        result = sevenCount;
        return result;
    }
}

import java.util.*;
import java.lang.*;

class Solution {

    public int primeFib(int n) {
        int count = 0;
        int fibA = 1;
        int fibB = 1;
        int fibCurrent = 0;
        while (count < n) {
            fibCurrent = fibA;
            fibA = fibB;
            fibB = fibCurrent + fibB;
            if (fibCurrent > 1) {
                boolean isPrime = true;
                if (fibCurrent < 2) {
                    isPrime = false;
                } else if (fibCurrent == 2) {
                    isPrime = true;
                } else if (fibCurrent % 2 == 0) {
                    isPrime = false;
                } else {
                    int sqrt = (int) Math.sqrt(fibCurrent);
                    for (int i = 3; i <= sqrt; i += 2) {
                        if (fibCurrent % i == 0) {
                            isPrime = false;
                            break;
                        }
                    }
                }
                if (isPrime) {
                    count++;
                    if (count == n) {
                        return fibCurrent;
                    }
                }
            }
        }
        return 0;
    }
}

