import java.util.*;
import java.lang.*;

class Solution {

    public String changeBase(int x, int base) {
        if (base == 1) {
            if (x < 0) {
                return "-" + "1".repeat(-x);
            } else {
                return "1".repeat(x);
            }
        }
        boolean negative = x < 0;
        if (negative) {
            x = -x;
        }
        if (x == 0) {
            return "0";
        }
        StringBuilder digits = new StringBuilder();
        int temp = x;
        while (temp != 0) {
            int r = temp % base;
            digits.append((char) ('0' + r));
            temp = temp / base;
        }
        if (negative) {
            digits.append('-');
        }
        return digits.reverse().toString();
    }
}

