class Solution {

    public int fib4(int n) {
        if (n == 0 || n == 1 || n == 3) {
            return 0;
        } else if (n == 2) {
            return 2;
        } else {
            int fib4_0 = 0;
            int fib4_1 = 0;
            int fib4_2 = 2;
            int fib4_3 = 0;
            int temp;
            for (int i = 4; i <= n; i++) {
                temp = fib4_3 + fib4_2 + fib4_1 + fib4_0;
                fib4_0 = fib4_1;
                fib4_1 = fib4_2;
                fib4_2 = fib4_3;
                fib4_3 = temp;
            }
            return fib4_3;
        }
    }
}

