class Solution {

    public double triangleArea(double a, double b, double c) {
        if (a <= 0 || b <= 0 || c <= 0) {
            return -1;
        }
        if ((a + b) <= c || (a + c) <= b || (b + c) <= a) {
            return -1;
        }
        double s = (a + b + c) / 2;
        double prod = s * (s - a) * (s - b) * (s - c);
        if (prod < 0) {
            prod = 0;
        }
        double area = Math.sqrt(prod);
        return Math.round(area * 100.0) / 100.0;
    }
}

