class Solution {

    public boolean isMultiplyPrime(int a) {
        if (a <= 1) {
            return false;
        }
        int count = 0;
        for (int factor = 2; factor * factor <= a; factor++) {
            while (a % factor == 0) {
                if (isPrime(factor)) {
                    count++;
                }
                a /= factor;
            }
        }
        if (a > 1 && isPrime(a)) {
            count++;
        }
        return count == 3;
    }

    private boolean isPrime(int n) {
        if (n <= 1) {
            return false;
        }
        if (n == 2) {
            return true;
        }
        if (n % 2 == 0) {
            return false;
        }
        int sqrt = (int) Math.sqrt(n);
        for (int i = 3; i <= sqrt; i += 2) {
            if (n % i == 0) {
                return false;
            }
        }
        return true;
    }
}

