        int shift = 4;
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c >= 'a' && c <= 'z') {
                int newCharNum = ((c - 'a' + shift) % 26) + 'a';
                result.append((char) newCharNum);
            } else if (c >= 'A' && c <= 'Z') {
                int newCharNum = ((c - 'A' + shift) % 26) + 'A';
                result.append((char) newCharNum);
            } else {
                result.append(c);
            }
        }
        return result.toString();
