class Solution {

    public String intersection(List<Integer> interval1, List<Integer> interval2) {
        int a1 = interval1.get(0);
        int b1 = interval1.get(1);
        int a2 = interval2.get(0);
        int b2 = interval2.get(1);
        int start = Math.max(a1, a2);
        int end = Math.min(b1, b2);
        if (start > end) {
            return "NO";
        }
        int len = end - start;
        boolean isPrime = false;
        if (len >= 2) {
            isPrime = true;
            if (len == 2) {
                // do nothing
            } else {
                int rem = len % 2;
                if (rem == 0) {
                    isPrime = false;
                } else {
                    for (int i = 3; i <= len; i += 2) {
                        rem = len % i;
                        if (rem == 0) {
                            isPrime = false;
                            break;
                        }
                        if (i * i > len) {
                            break;
                        }
                    }
                }
            }
        }
        return isPrime ? "YES" : "NO";
    }
}

