class Solution {

    public String filenameCheck(String file_name) {
        int digitCount = 0;
        int dotCount = 0;
        int dotPosition = 0;
        int fileLength = 0;
        int counter;
        char ch;
        String beforeDot;
        String afterDot;
        char firstChar;
        boolean validFlag = true;

        fileLength = 0;
        for (counter = 0; counter < 100 && counter < file_name.length(); counter++) {
            if (file_name.charAt(counter) == ' ') break;
            fileLength++;
        }

        if (fileLength == 0) return "No";

        for (counter = 0; counter < fileLength; counter++) {
            ch = file_name.charAt(counter);
            if (ch >= '0' && ch <= '9') digitCount++;
            if (ch == '.') {
                dotCount++;
                dotPosition = counter + 1;
            }
        }

        if (digitCount > 3) validFlag = false;
        if (dotCount != 1) validFlag = false;
        if (dotPosition == 1) validFlag = false;

        if (dotPosition > 0 && validFlag) {
            firstChar = file_name.charAt(0);
            if (!((firstChar >= 'a' && firstChar <= 'z') || (firstChar >= 'A' && firstChar <= 'Z')))
                validFlag = false;

            afterDot = file_name.substring(dotPosition);
            if (!afterDot.equals("txt") && !afterDot.equals("exe") && !afterDot.equals("dll"))
                validFlag = false;
        }

        return validFlag ? "Yes" : "No";
    }
}

