import java.util.*;
import java.lang.*;

class Solution {

    public String wordsInSentence(String sentence) {

        int last = sentence.length() - 1;
        while (last >= 0 && sentence.charAt(last) == ' ') {
            last--;
        }
        if (last < 0) {
            return "";
        }

        StringBuilder result = new StringBuilder();
        int pos = 0;
        while (pos <= last) {
            char ch = sentence.charAt(pos);
            if (ch == ' ') {
                pos++;
                continue;
            }

            int start = pos;
            while (pos <= last && sentence.charAt(pos) != ' ') {
                pos++;
            }
            int len = pos - start;

            if (isPrime(len)) {
                if (result.length() > 0) {
                    result.append(' ');
                }
                result.append(sentence, start, len);
            }
        }
        return result.toString();
    }

    private boolean isPrime(int n) {
        if (n <= 1) {
            return false;
        }
        for (int d = 2; d < n; d++) {
            if (n % d == 0) {
                return false;
            }
        }
        return true;
    }
}

