import java.util.*;
import java.lang.*;

class Solution {

    public List<Integer> orderByPoints(List<Integer> nums) {
        int[] sums = new int[5];
        for (int i = 0; i < 5; i++) {
            int num = nums.get(i);
            int sum = 0;
            if (num >= 0) {
                while (num != 0) {
                    int digit = Math.abs(num % 10);
                    sum += digit;
                    num /= 10;
                }
            } else {
                int temp = Math.abs(num);
                int firstDigit = 0;
                while (temp >= 10) {
                    temp /= 10;
                }
                firstDigit = temp;
                sum = -firstDigit;
                temp = Math.abs(num);
                while (temp >= 10) {
                    int digit = temp % 10;
                    sum += digit;
                    temp /= 10;
                }
            }
            sums[i] = sum;
        }
        for (int i = 0; i < 4; i++) {
            for (int j = i + 1; j < 5; j++) {
                if (sums[i] > sums[j]) {
                    int tempSum = sums[i];
                    sums[i] = sums[j];
                    sums[j] = tempSum;
                    int tempNum = nums.get(i);
                    nums.set(i, nums.get(j));
                    nums.set(j, tempNum);
                }
            }
        }
        List<Integer> result = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            result.add(nums.get(i));
        }
        return result;
    }
}

