class Solution {

    public int getMaxTriples(int n) {
        int count = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = i + 1; j <= n; j++) {
                for (int k = j + 1; k <= n; k++) {
                    int aI = i * i - i + 1;
                    int aJ = j * j - j + 1;
                    int aK = k * k - k + 1;
                    int sum = aI + aJ + aK;
                    if (sum % 3 == 0) {
                        count++;
                    }
                }
            }
        }
        return count;
    }
