class Solution {

    public int xOrY(int n, int x, int y) {
        boolean isPrime = true;
        if (n <= 1) {
            isPrime = false;
        } else if (n == 2) {
            isPrime = true;
        } else if (n % 2 == 0) {
            isPrime = false;
        } else {
            int sqrtN = (int) Math.sqrt(n);
            for (int i = 3; i <= sqrtN && isPrime; i += 2) {
                if (n % i == 0) {
                    isPrime = false;
                }
            }
        }
        return isPrime ? x : y;
    }
}

