class Solution {

    public String StrongestExtension(String class_name, List<String> extensions) {

        int bestIdx = 0;
        int bestStr = Integer.MIN_VALUE;

        for (int i = 0; i < extensions.size(); i++) {
            String ext = extensions.get(i);
            int up = 0, low = 0;
            for (int k = 0; k < ext.length(); k++) {
                char c = ext.charAt(k);
                if (c >= 'A' && c <= 'Z') up++;
                else if (c >= 'a' && c <= 'z') low++;
            }
            int curStr = up - low;
            if (curStr > bestStr) {
                bestStr = curStr;
                bestIdx = i;
            }
        }

        return class_name + "." + extensions.get(bestIdx);
    }
}

