            return true;
        }
        if (lenA == 0 || lenB > lenA) {
            return false;
        }
        String wa = a;
        String wb = b;
        for (int k = 0; k < lenB; k++) {
            String rot = wb.substring(k) + wb.substring(0, k);
            int maxPos = lenA - lenB + 1;
            for (int p = 0; p < maxPos; p++) {
                if (wa.substring(p, p + lenB).equals(rot.substring(0, lenB))) {
                    return true;
                }
            }
        }
        return false;
    }
}

