class Solution {

    public int doAlgebra(List<String> operator, List<Integer> operand) {
        int wsN = 3;
        for (int wsI = 0; wsI < wsN; wsI++) {
            if ("**".equals(operator.get(wsI))) {
                int wsA = operand.get(wsI);
                int wsB = operand.get(wsI + 1);
                int wsExpRes = 1;
                for (int wsK = 1; wsK <= wsB; wsK++) {
                    wsExpRes *= wsA;
                }
                operand.set(wsI, wsExpRes);
                for (int wsK = wsI; wsK < wsN - 1; wsK++) {
                    operator.set(wsK, operator.get(wsK + 1));
                    operand.set(wsK, operand.get(wsK + 1));
                }
                wsN--;
                wsI--;
            }
        }
        for (int wsI = 0; wsI < wsN; wsI++) {
            if ("*".equals(operator.get(wsI)) || "//".equals(operator.get(wsI))) {
                int wsA = operand.get(wsI);
                int wsB = operand.get(wsI + 1);
                if ("*".equals(operator.get(wsI))) {
                    int wsMulRes = wsA * wsB;
                    operand.set(wsI, wsMulRes);
                } else {
                    int wsDivRes = wsA / wsB;
                    int wsDivRem = wsA % wsB;
                    operand.set(wsI, wsDivRes);
                }
                for (int wsK = wsI; wsK < wsN - 1; wsK++) {
                    operator.set(wsK, operator.get(wsK + 1));
                    operand.set(wsK, operand.get(wsK + 1));
                }
                wsN--;
                wsI--;
            }
        }
        int result = operand.get(0);
        for (int wsI = 0; wsI < wsN; wsI++) {
            int wsB = operand.get(wsI + 1);
            if ("+".equals(operator.get(wsI))) {
                result += wsB;
            } else {
                result -= wsB;
            }
        }
        return result;
    }
}

import java.util.*;
